      </div>

      {error && (
        <p
          className="mt-3 rounded-xl bg-[#fbeceb] px-4 py-3 text-sm font-medium text-[#b3261e]"
          role="alert"
        >
          {error}
        </p>
      )}
    </div>
  );
}

