                aria-hidden
              />
              <span
                className="text-sm font-bold tracking-[-0.01em] text-[#18181f]"
                style={{ fontFamily: "var(--font-display)" }}
              >
                {documentType.label}
              </span>
              <span className="mt-2 text-xs leading-relaxed text-[#70685d]">
                {documentType.hint}
              </span>
            </button>
          );
        })}
      </div>
    </section>
  );
}

