vi.mock("next/font/google", () => {
  const loader = () => ({
    className: "mock-font",
    variable: "mock-font-variable",
    style: { fontFamily: "mock-font" },
  });
  return new Proxy(
    {},
    {
      get: (_target, prop) => {
        // Don't hijack `then`/`__esModule`/symbols, or the module namespace
        // looks like a thenable and `await import(...)` hangs forever.
        if (prop === "then" || prop === "__esModule" || typeof prop === "symbol") {
          return undefined;
        }
        return loader;
      },
    },
  );
});

